SET NOCOUNT ON;
BEGIN TRANSACTION;
IF OBJECT_ID(N'dbo.well_project_sample', N'U') IS NULL
BEGIN
    CREATE TABLE dbo.well_project_sample (
        id BIGINT IDENTITY(1,1) NOT NULL PRIMARY KEY,
        [month] NVARCHAR(20) NULL,
        receive_date DATE NULL,
        [type] NVARCHAR(100) NULL,
        sample_no NVARCHAR(100) NULL,
        raw_sample NVARCHAR(255) NULL,
        sample_name NVARCHAR(255) NULL,
        quantity INT NULL,
        remark NVARCHAR(1000) NULL,
        source NVARCHAR(100) NOT NULL,
        [year] SMALLINT NOT NULL
    );
END;
DELETE FROM dbo.well_project_sample WHERE [year] = 2025;
